import{_ as a,o as t,c as n,j as r,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"林意道具组","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/林意道具组.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/林意道具组.md"}'),o={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/林意道具组.md"};function d(b,e,_,l,i,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"林意道具组",tabindex:"-1"},[p("林意道具组 "),r("a",{class:"header-anchor",href:"#林意道具组","aria-label":'Permalink to "林意道具组"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调015")])])],-1),s('<h1 id="林意道具组-1" tabindex="-1">林意道具组 <a class="header-anchor" href="#林意道具组-1" aria-label="Permalink to &quot;林意道具组&quot;">​</a></h1><p>林意道具组<br> 干净核谐的马桶水<br> 5分/杯<br> 这是一杯神奇的马桶水，据生产者高价买来的证明显示完全无毒无害。<br> 当你喝下一杯马桶水，接下来的二十四小时内你的两腿根部中间位置会因为绝对不是变异的原因发光，亮度和一个大概率手电筒，这意味着二十四小时内只要不用衣物挡住这个部位就能提供光源，但需要注意作为光源的部位在黑夜里自然会清晰可见。</p><p>书上的蜂蜜<br> 5分/份<br> 在书上涂一份蜂蜜，然后舔干净，因为培养了兴趣，你会将书的内容在24小时内牢牢记住，但可惜的是，这个效果只对宗教相关的书籍生效。</p><p>发芽的土豆<br> 因为发现你不小心买了一个发芽的土豆，自由国正直的售货店员立刻报警并在三小时内追踪到你家赔偿了你买土豆的钱，所以这个土豆是免费的，但你需要支付250分的出警费才能拿到<br> 你可以自暴自弃地吃掉这个有毒的土豆，接下来的二十四小时内你会受到不可豁免的1点毒素异常点，但这种深刻的教训让你吃一堑长一智，二十四小时内你的回忆检定获得2士气加值。</p><p>地震纪念章<br> 250<br> 这枚地震纪念章证明了当年地震中日本小学生的传奇故事，只要佩戴这枚纪念章你就能感觉到他们的力量支持着你。由于根据时间推断他们现在的称号是“平成废宅”，所以二次元相关的学识检定（不包括任何攻击检定）获得1士气加值。</p><p>电线鸟<br> 20<br> 这是一只玩具鸟，能够飞到任何20M高度以内的电线上，你在破坏与这根电线相连的配电箱或者电线时你的攻击检定获得1士气加值，毕竟为了救一只鸟，停电又算什么呢？顺便一体，这只电线鸟是绝缘材料制作的玩具，不会被电坏，但这和你拯救小鸟的英勇行为并不冲突。</p><p>德意志螺丝<br> 20<br> 你只需要花六个小时认真严谨地拧好这个螺丝，那么十二小时内你的意志豁免检定获得1点士气加值，不会叠加，这是对你专注的认可，至于拧螺丝这种小事为什么要你这个工作繁忙才能优秀的轮回者干，那就不清楚了。</p><p>必须洗七遍的盘子<br> 250<br> 这个盘子必须洗七遍，你可以在任何时候拿出这个盘子进行清洗，给周围的人一种你很忙的错觉，这是一个无支线思维控制效果，特殊的是，这个盘子必须洗七遍，所以一旦你开始清洗，至少一小时后才能停下。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
